package com.trademaster.ims.mobile.reviews.dto;
import jakarta.validation.constraints.*;import java.math.BigDecimal;import java.time.Instant;import java.util.List;
public final class ReviewDtos{private ReviewDtos(){}public record ReviewSummaryResponse(Long productId,BigDecimal averageRating,long reviewCount){}public record ReviewResponse(String reviewNumber,Long productId,String productName,String customerDisplayName,String orderNumber,Integer rating,String title,String comment,String status,Instant createdAt,Instant updatedAt){}public record ReviewableItemResponse(String orderNumber,Long orderItemId,Long productId,String productName,String variationName,String imageUrl,boolean delivered,boolean alreadyReviewed,String existingReviewNumber,String existingReviewStatus){}public record ReviewRequest(@NotBlank String orderNumber,@NotNull Long orderItemId,@Min(1)@Max(5)Integer rating,@Size(max=120)String title,@NotBlank @Size(max=1000)String comment){}public record ReviewUpdateRequest(@Min(1)@Max(5)Integer rating,@Size(max=120)String title,@Size(max=1000)String comment){}public record ModerationRequest(@NotBlank String status,@Size(max=500)String note){}public record MyReviewsResponse(List<ReviewResponse>reviews){} }